INSERT INTO komentar_pengumuman ("id_pengumuman", "id_user", "isi_komentar", "createdAt", "updatedAt") VALUES
(1, 6, 'Siap, laksanakan. Berarti tidak boleh share screen ya?', '2025-03-05 14:20:10.112046+07', '2025-03-05 14:20:10.112046+07'),
(1, 7, 'Paham min, kejujuran nomor satu.', '2025-03-05 15:45:33.212046+07', '2025-03-05 15:45:33.212046+07'),
(1, 2, 'Betul, jika ketahuan ada kesamaan jawaban, keduanya akan didiskualifikasi.', '2025-03-05 16:10:05.982046+07', '2025-03-05 16:10:05.982046+07'),

(2, 8, 'Min, kalau screenshot-nya kepotong sedikit tapi teksnya jelas boleh?', '2025-03-02 10:15:22.442046+07', '2025-03-02 10:15:22.442046+07'),
(2, 3, 'Usahakan full window ya supaya konteksnya terlihat jelas.', '2025-03-02 11:05:12.772046+07', '2025-03-02 11:05:12.772046+07'),
(2, 9, 'Terima kasih infonya, sangat membantu agar tidak salah format.', '2025-03-02 14:22:01.002046+07', '2025-03-02 14:22:01.002046+07'),

(3, 10, 'Waduh, Tugas 1 kemarin saya kumpulnya .docx, perlu diulang?', '2025-03-10 21:10:45.322046+07', '2025-03-10 21:10:45.322046+07'),
(3, 4, 'Tugas 1 tidak apa-apa, mulai Tugas 2 saja yang wajib PDF.', '2025-03-10 22:05:11.982046+07', '2025-03-10 22:05:11.982046+07'),
(3, 11, 'PDF lebih rapi sih, setuju min.', '2025-03-11 08:30:15.552046+07', '2025-03-11 08:30:15.552046+07'),

(4, 12, 'Semangat pagi! Izin lanjut ke Tugas 3 ya min.', '2025-03-12 08:45:00.122046+07', '2025-03-12 08:45:00.122046+07'),
(4, 13, 'Gas terus jangan kasih kendor!', '2025-03-12 09:15:22.662046+07', '2025-03-12 09:15:22.662046+07'),
(4, 5, 'Silakan, pastikan tugas sebelumnya sudah di-review ya.', '2025-03-12 10:30:05.982046+07', '2025-03-12 10:30:05.982046+07'),

(5, 6, 'Wah syukurlah, jadi bisa lebih fokus ke kualitas daripada buru-buru.', '2025-03-15 09:10:11.332046+07', '2025-03-15 09:10:11.332046+07'),
(5, 7, 'Terima kasih kebijakannya Mimin Labkom.', '2025-03-15 10:05:44.882046+07', '2025-03-15 10:05:44.882046+07'),
(5, 8, 'Berarti kalau minggu ini belum selesai masih aman ya min?', '2025-03-15 11:30:22.112046+07', '2025-03-15 11:30:22.112046+07'),

(6, 1, 'Tolong diperhatikan ya teman-teman, poin utama kita adalah eksplorasi.', '2025-03-18 17:05:12.442046+07', '2025-03-18 17:05:12.442046+07'),
(6, 9, 'Maaf min, kemarin memang agak ngejar waktu. Kedepannya akan diperbaiki.', '2025-03-18 19:22:01.002046+07', '2025-03-18 19:22:01.002046+07'),
(6, 10, 'Terima kasih evaluasinya, sangat menampar untuk lebih teliti lagi.', '2025-03-18 20:15:33.772046+07', '2025-03-18 20:15:33.772046+07'),

(7, 11, 'Waduh, berarti jam 3 sore sudah harus kosong ya labnya?', '2025-03-20 09:30:15.552046+07', '2025-03-20 09:30:15.552046+07'),
(7, 12, 'Siap, segera dikondisikan sebelum jam 3.', '2025-03-20 10:15:22.662046+07', '2025-03-20 10:15:22.662046+07'),
(7, 4, 'Jangan lupa simpan semua file di cloud sebelum PC dimatikan.', '2025-03-20 11:45:05.982046+07', '2025-03-20 11:45:05.982046+07'),

(8, 13, 'Label namanya pakai kertas atau gimana min?', '2025-03-22 13:10:11.332046+07', '2025-03-22 13:10:11.332046+07'),
(8, 2, 'Pakai lakban kertas saja di casing depan supaya tidak tertukar.', '2025-03-22 14:05:44.882046+07', '2025-03-22 14:05:44.882046+07'),
(8, 6, 'Selamat berjuang untuk akreditasinya tim Labkom!', '2025-03-22 15:30:22.112046+07', '2025-03-22 15:30:22.112046+07'),

(9, 7, 'Min, ITSEC itu lombanya tentang apa ya secara spesifik?', '2025-03-25 11:20:10.112046+07', '2025-03-25 11:20:10.112046+07'),
(9, 8, 'Ada yang mau bareng daftar Compfest? Kurang 1 orang lagi nih.', '2025-03-25 13:45:33.212046+07', '2025-03-25 13:45:33.212046+07'),
(9, 9, 'Ayo gas Gemastik! Nanti saya DM ya min.', '2025-03-25 15:10:05.982046+07', '2025-03-25 15:10:05.982046+07'),

(10, 10, 'Tugas 6 saya dikit lagi kelar min, ditunggu update kelompoknya.', '2025-03-28 09:15:22.442046+07', '2025-03-28 09:15:22.442046+07'),
(10, 11, 'Semoga dapat kelompok yang asik kerjanya.', '2025-03-28 11:05:12.772046+07', '2025-03-28 11:05:12.772046+07'),
(10, 3, 'Selesaikan dulu tugas masing-masing, nanti pembagiannya random agar adil.', '2025-03-28 14:22:01.002046+07', '2025-03-28 14:22:01.002046+07'),

(11, 12, 'Sedih juga ya sudah mau berakhir pelatihannya.', '2025-03-30 15:10:45.322046+07', '2025-03-30 15:10:45.322046+07'),
(11, 13, 'Persiapan mental buat wawancara hari senin!', '2025-03-30 16:30:15.552046+07', '2025-03-30 16:30:15.552046+07'),
(11, 1, 'Persiapkan diri dengan baik, tunjukkan hasil belajar kalian selama ini.', '2025-03-30 18:05:11.982046+07', '2025-03-30 18:05:11.982046+07');